// Responsive Mixins
// --------------------------------------------------


// Creates a fixed width for the grid based on the screen size
// ---------------------------------------------------------------------------------

@mixin make-grid-widths($widths: $grid-widths, $breakpoints: $screen-breakpoints) {
  @each $breakpoint, $width in $widths {
    @include media-breakpoint-up($breakpoint, $breakpoints) {
      width: $width;
    }
  }

  max-width: 100%;
}

// Adds padding to the element based on breakpoints
// ---------------------------------------------------------------------------------

@mixin make-breakpoint-padding($paddings) {
  @each $breakpoint in map-keys($paddings) {
    @include media-breakpoint-up($breakpoint) {
      $padding: map-get($paddings, $breakpoint);

      @include padding($padding);
    }
  }
}

label {
  em.highlight {
    position: relative;
    left: calc(var(--base-size-4) * -1);
    // stylelint-disable-next-line primer/spacing
    padding: 2px var(--base-size-4);
    font-style: normal;
    background: var(--bgColor-attention-muted, var(--color-attention-subtle));
    // stylelint-disable-next-line primer/borders
    border-radius: $border-radius;
  }
}

dt, // TODO: Deprecate
    .form-group-header {
      label {
        display: inline-block;
        // stylelint-disable-next-line primer/spacing
        margin: 5px 0 0;
        color: var(--fgColor-muted, var(--color-fg-muted));
      }

      img {
        position: relative;
        // stylelint-disable-next-line primer/spacing
        top: -2px;
      }
    }

&:active,
  &.active,
  .open > &.dropdown-toggle {
    color: $color;
    background-color: darken($background, 10%);
    background-image: none;
    border-color: darken($border, 12%);

    &:hover,
    &:focus,
    &.focus {
      color: $color;
      background-color: darken($background, 17%);
      border-color: darken($border, 25%);
    }
  }
